repl("Extracting key guideline text", "function pickLinesGuidelines(txt) {
  const keys = /(fee|\$|submittable|submit|poem|poetry|simultaneous|reading period|open|closed|unpublished|previously published|pages|window|deadline|portal|email|mail|year[- ]round|August|September|October|November|December|January|February|March|April|May|June|July)/i;
  return txt.split(/\n+/).map(x=>x.trim()).filter(Boolean).filter(l=>keys.test(l)).slice(0,80).join('\n');
}
for (const idx of [1,4,5,6,8,9,10,11,12]) {
  await tabs[idx].bringToFront();
  const txt = await page.locator('body').innerText({timeout:10000}).catch(e=>'ERR '+e.message);
  console.log('\n### TAB '+idx+' '+(await page.title())+' '+page.url()+'\n'+pickLinesGuidelines(txt));
}")

